'use client'

import { FunnelIcon, PlusIcon } from 'lucide-react'
import type React from 'react'
import { useState } from 'react'

import { Badge } from '../components/badge'
import { Button } from '../components/button'
import { Form } from '../components/form'
import {
  Popover,
  PopoverDescription,
  PopoverPopup,
  PopoverTitle,
  PopoverTrigger,
} from '../components/popover'
import { FilterConditionRow } from './filter-condition-row'
import {
  createFilterConditionDraft,
  type FilterBuilderAttribute,
  type FilterCondition,
  type FilterConditionDraft,
  isCompleteFilterCondition,
} from './types'

export interface FilterBuilderProps {
  attributes: readonly FilterBuilderAttribute[]
  onValueChange: (conditions: FilterCondition[]) => void
  triggerLabel?: string
  value: readonly FilterCondition[]
}

function createDraft(value: readonly FilterCondition[]): FilterConditionDraft[] {
  return value.length > 0
    ? value.map((condition) => createFilterConditionDraft(condition))
    : [createFilterConditionDraft()]
}

export function FilterBuilder({
  attributes,
  onValueChange,
  triggerLabel = 'Filtrar',
  value,
}: Readonly<FilterBuilderProps>): React.ReactElement {
  const [open, setOpen] = useState(false)
  const [draft, setDraft] = useState<FilterConditionDraft[]>(() => createDraft(value))
  const canApply = draft.length > 0 && draft.every(isCompleteFilterCondition)

  function handleOpenChange(nextOpen: boolean): void {
    setDraft(createDraft(value))
    setOpen(nextOpen)
  }

  function updateCondition(index: number, condition: FilterConditionDraft): void {
    setDraft((current) =>
      current.map((currentCondition, currentIndex) =>
        currentIndex === index ? condition : currentCondition,
      ),
    )
  }

  function removeCondition(index: number): void {
    setDraft((current) => {
      const remaining = current.filter((_, currentIndex) => currentIndex !== index)
      return remaining.length > 0 ? remaining : [createFilterConditionDraft()]
    })
  }

  function apply(event: React.FormEvent<HTMLFormElement>): void {
    event.preventDefault()
    if (!canApply) {
      return
    }

    const completeConditions = draft.filter(isCompleteFilterCondition).map((condition) => ({
      attributeId: condition.attributeId,
      operator: condition.operator,
      value: condition.value,
    }))
    onValueChange(completeConditions)
    setOpen(false)
  }

  function clear(): void {
    onValueChange([])
    setDraft([createFilterConditionDraft()])
  }

  function cancel(): void {
    setOpen(false)
  }

  const isFilterEnabled = value.length > 0
  return (
    <Popover onOpenChange={handleOpenChange} open={open}>
      <PopoverTrigger
        render={<Button aria-label={triggerLabel} type="button" variant="secondary" />}
      >
        <FunnelIcon />
        {triggerLabel}
        {isFilterEnabled && (
          <Badge aria-label={`${value.length} filtros aplicados`} variant="secondary">
            {value.length}
          </Badge>
        )}
      </PopoverTrigger>
      <PopoverPopup align="center" className="w-[min(36rem,var(--available-width))]">
        <Form className="grid gap-4" onSubmit={apply}>
          <div className="grid gap-1">
            <PopoverTitle>Filtros</PopoverTitle>
            <PopoverDescription>
              Monte as condições e aplique quando o filtro estiver completo.
            </PopoverDescription>
          </div>

          <div className="grid gap-2">
            {draft.map((condition, index) => (
              <FilterConditionRow
                attributes={attributes}
                condition={condition}
                index={index}
                key={condition.draftId}
                onChange={(nextCondition) => updateCondition(index, nextCondition)}
                onRemove={() => removeCondition(index)}
              />
            ))}
          </div>

          <Button
            onClick={() => setDraft((current) => [...current, createFilterConditionDraft()])}
            size="sm"
            type="button"
            variant="ghost"
          >
            <PlusIcon />
            Adicionar condição
          </Button>

          <div className="flex flex-wrap items-center justify-between gap-2 border-t pt-4">
            <Button onClick={clear} size="sm" type="button" variant="ghost">
              Limpar filtros
            </Button>
            <div className="flex items-center gap-2">
              <Button onClick={cancel} size="sm" type="button" variant="outline">
                Cancelar
              </Button>
              <Button disabled={!canApply} size="sm" type="submit">
                Aplicar
              </Button>
            </div>
          </div>
        </Form>
      </PopoverPopup>
    </Popover>
  )
}

'use client'

import { XIcon } from 'lucide-react'
import type React from 'react'

import { Button } from '../components/button'
import { Group, GroupSeparator, GroupText } from '../components/group'
import {
  Select,
  SelectItem,
  SelectLabel,
  SelectPopup,
  SelectTrigger,
  SelectValue,
} from '../components/select'
import type { FilterBuilderAttribute, FilterConditionDraft } from './types'

interface FilterConditionRowProps {
  attributes: readonly FilterBuilderAttribute[]
  condition: FilterConditionDraft
  index: number
  onChange: (condition: FilterConditionDraft) => void
  onRemove: () => void
}

export function FilterConditionRow({
  attributes,
  condition,
  index,
  onChange,
  onRemove,
}: Readonly<FilterConditionRowProps>): React.ReactElement {
  const selectedAttribute = attributes.find((attribute) => attribute.id === condition.attributeId)
  const attributeItems = attributes.map((attribute) => ({
    label: attribute.label,
    value: attribute.id,
  }))
  const rowNumber = index + 1

  function selectAttribute(attributeId: string): void {
    const nextAttribute = attributes.find((attribute) => attribute.id === attributeId)
    const operator = nextAttribute?.operators.some((option) => option.value === condition.operator)
      ? condition.operator
      : ''
    const value = nextAttribute?.options.some((option) => option.value === condition.value)
      ? condition.value
      : ''

    onChange({ ...condition, attributeId, operator, value })
  }

  return (
    <Group aria-label={`Condição ${rowNumber}`} className="max-w-full flex-wrap sm:flex-nowrap">
      <GroupText className="h-8 min-w-14 justify-center px-2.5">
        {index === 0 ? 'Onde' : 'E'}
      </GroupText>
      <GroupSeparator className="hidden sm:block" />
      <Select
        items={attributeItems}
        onValueChange={(value) => selectAttribute(String(value ?? ''))}
        value={condition.attributeId || null}
      >
        <SelectTrigger aria-label={`Atributo da condição ${rowNumber}`} className="min-w-36 flex-1">
          <SelectValue placeholder="Atributo" />
        </SelectTrigger>
        <SelectPopup alignItemWithTrigger={false}>
          <SelectLabel>Atributo</SelectLabel>
          {attributes.map((attribute) => (
            <SelectItem key={attribute.id} value={attribute.id}>
              {attribute.label}
            </SelectItem>
          ))}
        </SelectPopup>
      </Select>
      <GroupSeparator className="hidden sm:block" />
      <Select
        disabled={!selectedAttribute}
        items={selectedAttribute?.operators ?? []}
        onValueChange={(value) =>
          onChange({ ...condition, operator: String(value ?? ''), value: '' })
        }
        value={condition.operator || null}
      >
        <SelectTrigger aria-label={`Operador da condição ${rowNumber}`} className="min-w-32 flex-1">
          <SelectValue placeholder="Operador" />
        </SelectTrigger>
        <SelectPopup alignItemWithTrigger={false}>
          <SelectLabel>Operador</SelectLabel>
          {selectedAttribute?.operators.map((operator) => (
            <SelectItem key={operator.value} value={operator.value}>
              {operator.label}
            </SelectItem>
          ))}
        </SelectPopup>
      </Select>
      <GroupSeparator className="hidden sm:block" />
      <Select
        disabled={!selectedAttribute || !condition.operator}
        items={selectedAttribute?.options ?? []}
        onValueChange={(value) => onChange({ ...condition, value: String(value ?? '') })}
        value={condition.value || null}
      >
        <SelectTrigger aria-label={`Valor da condição ${rowNumber}`} className="min-w-36 flex-1">
          <SelectValue placeholder="Valor" />
        </SelectTrigger>

        <SelectPopup alignItemWithTrigger={false}>
          <SelectLabel>Valor</SelectLabel>
          {selectedAttribute?.options.map((option) => (
            <SelectItem key={option.value} value={option.value}>
              {option.label}
            </SelectItem>
          ))}
        </SelectPopup>
      </Select>
      <GroupSeparator className="hidden sm:block" />

      <Button
        aria-label={`Remover condição ${rowNumber}`}
        onClick={onRemove}
        type="button"
        variant="outline"
      >
        <XIcon />
      </Button>
    </Group>
  )
}

export interface FilterBuilderOption {
  label: string
  value: string
}

export interface FilterBuilderAttribute {
  id: string
  label: string
  operators: readonly FilterBuilderOption[]
  options: readonly FilterBuilderOption[]
  valueType: 'select'
}

export interface FilterCondition {
  attributeId: string
  operator: string
  value: string
}

export interface FilterConditionDraft extends FilterCondition {
  draftId: string
}

let draftSequence = 0

function createDraftId(): string {
  draftSequence += 1
  return `filter-condition-${draftSequence}`
}

export function createFilterConditionDraft(condition?: FilterCondition): FilterConditionDraft {
  return {
    attributeId: condition?.attributeId ?? '',
    draftId: createDraftId(),
    operator: condition?.operator ?? '',
    value: condition?.value ?? '',
  }
}

export function isCompleteFilterCondition(condition: FilterCondition): boolean {
  return Boolean(condition.attributeId && condition.operator && condition.value)
}

import { type ClassValue, clsx } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]): string {
  return twMerge(clsx(inputs))
}
